using System;
using System.IO;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;

namespace YourApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class UploadsController : ControllerBase
    {
        private readonly IWebHostEnvironment _env;
        private readonly FileExtensionContentTypeProvider _contentTypeProvider;

        public UploadsController(IWebHostEnvironment env)
        {
            _env = env;
            _contentTypeProvider = new FileExtensionContentTypeProvider();
        }

        [HttpGet("{filename}")]
        public async Task<IActionResult> Get(string filename)
        {
            if (string.IsNullOrWhiteSpace(filename))
                return BadRequest();

            filename = filename.Trim();

            if (filename.Contains("..", StringComparison.Ordinal) ||
                filename.Contains('/', StringComparison.Ordinal) ||
                filename.Contains('\\', StringComparison.Ordinal) ||
                Path.IsPathRooted(filename))
            {
                return BadRequest();
            }

            var uploadsRoot = Path.Combine(_env.ContentRootPath, "uploads");
            var fullPath = Path.GetFullPath(Path.Combine(uploadsRoot, filename));

            if (!fullPath.StartsWith(Path.GetFullPath(uploadsRoot), StringComparison.OrdinalIgnoreCase))
                return BadRequest();

            if (!System.IO.File.Exists(fullPath))
                return NotFound();

            if (!_contentTypeProvider.TryGetContentType(fullPath, out var contentType))
                contentType = "application/octet-stream";

            var stream = new FileStream(fullPath, FileMode.Open, FileAccess.Read, FileShare.Read, 64 * 1024, useAsync: true);
            return File(stream, contentType, enableRangeProcessing: true);
